import { O11yMetrics } from '../../common/metric';
/**
 * Represents the BatchAllSpanProcessorTelemetry class which extends O11yMetrics.
 * This class provides metrics related to the Batch All Span Processor's behavior.
 * @class
 * @extends {O11yMetrics}
 */
export default class BatchAllSpanProcessorTelemetry extends O11yMetrics {
    /**
     * Represents the metric `bsp.spans.dropped`.
     * This metric represents the number of spans that couldn't be enqueued by the Batch All Span Processor because the queue was full.
     * @type {Counter}
     * @private
     * @readonly
     */
    private readonly _droppedSpansMetric;
    /**
     * Represents the metric `bsp.spans.processed`.
     * This metric represents the number of spans attempted to be exported by the Batch All Span Processor.
     * @type {Counter}
     * @private
     * @readonly
     */
    private readonly _processedSpansMetric;
    /**
     * Represents the metric `bsp.spans.processed.export.failed`.
     * This metric represents the number of processed spans by the Batch All Span Processor that failed to be exported.
     * @type {Counter}
     * @private
     * @readonly
     */
    private readonly _exportSpansFailedMetric;
    /**
     * Represents the metric `bsp.spans.processed.export.sent`.
     * This metric represents the number of spans successfully exported by the Batch All Span Processor.
     * @type {Counter}
     * @private
     * @readonly
     */
    private readonly _exportSpansSentMetric;
    /**
     * Represents the metric `bsp.queue.size`.
     * This metric represents the estimated number of spans enqueued by the Batch All Span Processor that are waiting to be exported.
     * @type {ObservableGauge}
     * @private
     * @readonly
     */
    private readonly _queueSizeMetric;
    /**
     * Represents the metric `bsp.queue.capacity`.
     * This metric represents the maximum number of spans that the Batch All Span Processor can enqueue at once.
     * @type {ObservableGauge}
     * @private
     * @readonly
     */
    private readonly _queueCapacityMetric;
    /**
     * Represents the metric `bsp.queue.batch.export.time`.
     * This metric represents the time taken to export a batch of spans queued.
     * @type {Histogram}
     * @private
     * @readonly
     */
    private readonly _queueExportTime;
    /**
     * Represents the metric `bsp.batch.size`.
     * This metric represents the estimated number of spans of the Batch All Span Processor that will be attempted to be exported at once.
     * @type {ObservableGauge}
     * @private
     * @readonly
     */
    private readonly _batchSizeMetric;
    /**
     * Represents the metric `bsp.batch.capacity`.
     * This metric represents the maximum number of spans that the Batch All Span Processor will attempt to export at once.
     * @type {ObservableGauge}
     * @private
     * @readonly
     */
    private readonly _batchCapacityMetric;
    /**
     * Creates an instance of BatchAllSpanProcessorTelemetry.
     */
    constructor();
    /**
     * Increments the metric `bsp.spans.dropped` by the specified amount.
     * @param total The amount to increment the metric by.
     */
    incrementDroppedSpansMetric: (total: number) => void;
    /**
     * Increments the metric `bsp.spans.processed` by the specified amount.
     * @param total The amount to increment the metric by.
     */
    incrementProcessedSpansMetric: (total: number) => void;
    /**
     * Increments the metric `bsp.spans.processed.export.failed` by the specified amount.
     * @param total The amount to increment the metric by.
     */
    incrementExportSpansFailedMetric: (total: number) => void;
    /**
     * Increments the metric `bsp.spans.processed.export.sent` by the specified amount.
     * @param total The amount to increment the metric by.
     */
    incrementExportSpansSentMetric: (total: number) => void;
    /**
     * Observes the metric `bsp.queue.size` with the specified callback.
     * @param queueSize The callback function returning the queue size.
     */
    observeQueueSizeMetric: (queueSize: () => number) => void;
    /**
     * Observes the metric `bsp.queue.capacity` with the specified callback.
     * @param queueCapacity The callback function returning the queue capacity.
     */
    observeQueueCapacityMetric: (queueCapacity: number) => void;
    /**
     * Records the metric `bsp.queue.batch.export.time` with the specified time spent and success.
     * @param timeSpent The time spent to export a batch of spans queued.
     * @param success A boolean indicating whether the export was successful or not.
     */
    recordExportQueueTime: (timeSpent: number, success: boolean) => void;
    /**
     * Observes the metric `bsp.batch.size` with the specified callback.
     * @param batchSize The callback function returning the batch size.
     */
    observeBatchSizeMetric: (batchSize: () => number) => void;
    /**
     * Observes the metric `bsp.batch.capacity` with the specified callback.
     * @param batchCapacity The callback function returning the batch capacity.
     */
    observeBatchCapacityMetric: (batchCapacity: number) => void;
}
